      {/* Tabs Navigation */}
      <div className="flex overflow-x-auto custom-scrollbar pb-2 gap-2">
        {tabs.map(tab => {
          const isActive = activeTab === tab.id;
          const Icon = tab.icon;
          return (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={clsx(
                "flex items-center gap-2 px-5 py-2.5 rounded-xl font-bold text-sm whitespace-nowrap transition-all duration-300",
                isActive 
                  ? "bg-accent text-white shadow-[0_0_20px_rgba(168,85,247,0.4)]" 
                  : "bg-white/[0.03] text-secondary hover:bg-white/[0.08] hover:text-primary border border-white/[0.05]"
              )}
            >
              <Icon size={16} className={isActive ? "text-white" : "text-tertiary"} />
              {tab.label}
            </button>
          );
        })}
      </div>

      {/* Tab Content Area */}
      <AnimatePresence mode="wait">
        <motion.div
          key={activeTab}
          initial={{ opacity: 0, y: 10 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -10 }}
          transition={{ duration: 0.25 }}
        >
          {chiefQuery.isLoading ? (
            <div className="flex items-center justify-center py-20">
              <div className="w-8 h-8 border-2 border-accent/30 border-t-accent rounded-full animate-spin" />
            </div>
          ) : chiefQuery.isError ? (
            <div className="p-8 text-center">
              <p className="text-red-400 font-bold text-sm">Failed to load clan data.</p>
              <p className="text-tertiary text-xs mt-1">{chiefQuery.error?.message}</p>
            </div>
          ) : (
            <>
              {activeTab === 'dashboard' && <ChiefDashboardTab clan={chiefQuery.data} />}
              {activeTab === 'members' && <ChiefMembersTab clan={chiefQuery.data} />}
              {activeTab === 'review' && <ChiefReviewTab clan={chiefQuery.data} />}
              {activeTab === 'notices' && <ChiefNoticeTab clan={chiefQuery.data} />}
            </>
          )}
        </motion.div>
      </AnimatePresence>
    </div>
  );
};

export default ClanChiefPanel;

import React, { useState } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { motion, AnimatePresence } from 'framer-motion';
import toast from 'react-hot-toast';
import {
  FiUsers,
  FiShield,
  FiStar,
  FiTrendingUp,
  FiLogOut,
  FiSearch,
  FiCheckCircle,
  FiClock,
  FiMessageSquare,
  FiAward,
  FiTarget,
  FiX,
  FiTrash2,
  FiSend,
} from 'react-icons/fi';
import PageHeader from '../components/PageHeader';
import Card from '../components/Card';
import BaseCard from '../components/BaseCard';
import SkeletonCard from '../components/SkeletonCard';
import EmptyState from '../components/EmptyState';
import ConfirmDialog from '../components/ConfirmDialog';
import MemberHoverCard from '../components/MemberHoverCard';
import { api } from '../lib/api';
import { useAuth } from '../context/useAuth';

const InternalClanChat = ({ clanId }) => {
  const { user } = useAuth();
  const [message, setMessage] = useState('');

  const queryClient = useQueryClient();

  const { data: messages = [], isLoading } = useQuery({
    queryKey: ['chat', clanId],
    queryFn: async () => {
      if (!clanId) return [];
      const res = await api.get(`/api/chat/${clanId}`);
      return res.data.data;
    },
    enabled: !!clanId,
    refetchInterval: 5000
  });

  const handleSend = async (e) => {
    e.preventDefault();
    if (!message.trim()) return;
    const text = message;
    setMessage('');
    try {
      await api.post(`/api/chat/${clanId}`, { content: text });
      queryClient.invalidateQueries(['chat', clanId]);
    } catch {
      setMessage(text); // restore on error
      toast.error('Failed to send message');
    }
  };

  return (
    <div className="h-full flex flex-col relative">
      <div className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar max-h-[400px]">
        {isLoading ? (
          <p className="text-secondary text-sm text-center">Establishing secure connection...</p>
        ) : messages.length === 0 ? (
          <p className="text-secondary text-sm text-center">No transmissions yet. Be the first.</p>
        ) : (
          messages.map(msg => {
            const isMe = msg.sender?._id === user?.id;
            return (
              <div key={msg._id} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'}`}>
                <div className="flex items-center gap-2 mb-1">
                  <span className="text-[10px] font-black uppercase text-tertiary">
                    {msg.sender?.username || 'Unknown'}
                  </span>
                  {msg.sender?.role === 'clan-chief' && (
                    <span className="text-[8px] bg-red-500/20 text-red-400 px-1.5 py-0.5 rounded font-black tracking-widest uppercase">Chief</span>
                  )}
                </div>
                <div className={`max-w-[85%] rounded-xl px-3 py-2 text-sm ${isMe ? 'bg-accent/20 text-primary border border-accent/30 rounded-tr-none' : 'bg-white/5 text-secondary border border-white/5 rounded-tl-none'}`}>
                  {msg.content}
                </div>
              </div>
            );
          })
        )}
      </div>

      <div className="p-3 border-t border-glass-border/40 mt-auto">
        <form onSubmit={handleSend} className="relative">
          <input
            type="text"
            value={message}
            onChange={e => setMessage(e.target.value)}
            placeholder="Transmit message..."
            className="w-full bg-white/5 border border-white/10 rounded-xl py-2 pl-3 pr-10 text-sm text-primary placeholder-tertiary focus:outline-none focus:border-accent/50 transition-colors"
          />
          <button 
            type="submit"
            disabled={!message.trim()}
            className="absolute right-1 top-1/2 -translate-y-1/2 w-7 h-7 flex items-center justify-center rounded-lg bg-accent/20 text-accent hover:bg-accent hover:text-white disabled:opacity-50 disabled:hover:bg-accent/20 disabled:hover:text-accent transition-colors"
          >
            <FiSend className="text-sm" />
          </button>
        </form>
