        <div
          className="relative overflow-hidden rounded-2xl p-8 group"
          style={{
            background: "linear-gradient(135deg, rgba(10,10,22,1) 0%, rgba(15,10,32,1) 60%, rgba(10,10,22,1) 100%)",
            border: "1px solid rgba(255,255,255,0.07)",
