const ChiefDashboardTab = ({ clan }) => {
  const queryClient = useQueryClient();
  const [warningModal, setWarningModal] = useState({ open: false, user: null, message: '' });

  const approveMutation = useMutation({
    mutationFn: async (userId) => {
      const res = await api.post(`/api/clans/${clan._id}/approve/${userId}`);
      return res.data;
    },
    onSuccess: () => {
      toast.success('Join request approved');
      queryClient.invalidateQueries(['chief-clan-info']);
    }
  });

  const rejectMutation = useMutation({
    mutationFn: async (userId) => {
      const res = await api.post(`/api/clans/${clan._id}/reject/${userId}`);
      return res.data;
    },
    onSuccess: () => {
      toast.success('Join request rejected');
      queryClient.invalidateQueries(['chief-clan-info']);
    }
  });

  const warnMutation = useMutation({
    mutationFn: async ({ userId, message }) => {
      const res = await api.post(`/api/users/${userId}/warn`, { message });
      return res.data;
    },
    onSuccess: () => {
      toast.success('Warning sent and user flagged.');
      setWarningModal({ open: false, user: null, message: '' });
      queryClient.invalidateQueries(['chief-clan-info']);
    }
  });

  if (!clan) return (
    <div className="flex items-center justify-center py-20">
      <div className="w-8 h-8 border-2 border-accent/30 border-t-accent rounded-full animate-spin" />
    </div>
  );

  const members = clan.members || [];
  const activeCount = members.filter(m => m.status !== 'Warned' && m.status !== 'Inactive').length;
  const warnedCount = members.filter(m => m.status === 'Warned').length;
  const pendingReviews = clan.requests?.length ?? 0;

  // Compute real completion rate: avg of (solvedProblems / target) across members
  const TARGET_PROBLEMS = 5;
  const totalSolved = members.reduce((sum, m) => sum + (m.solvedProblems || 0), 0);
  const totalPossible = members.length * TARGET_PROBLEMS;
  const completionRate = totalPossible > 0 ? Math.round((totalSolved / totalPossible) * 100) : 0;

  const circleRadius = 40;
  const circleCircumference = 2 * Math.PI * circleRadius;
  const strokeDashoffset = circleCircumference - (completionRate / 100) * circleCircumference;

  return (
    <div className="space-y-6">

      {/* 4 Stat Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4">
        <StatCard title="Total Members" value={members.length} subtitle="Active Roster" icon={FiUsers} colorClass="bg-blue-500/20 text-blue-400" />
        <StatCard title="Active This Week" value={activeCount} subtitle="Logged in" icon={FiActivity} colorClass="bg-green-500/20 text-green-400" />
        <StatCard title="At Risk / Warned" value={warnedCount} subtitle="Needs attention" icon={FiAlertTriangle} colorClass="bg-red-500/20 text-red-400" />
        <StatCard title="Pending Reviews" value={pendingReviews} subtitle="Code submissions" icon={FiFileText} colorClass="bg-purple-500/20 text-purple-400" />
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">

        {/* Left Col: Ring & Quick Actions */}
        <div className="space-y-6">
          <BaseCard className="p-6 flex flex-col items-center justify-center relative overflow-hidden group">
            <div className="absolute top-0 right-0 w-32 h-32 bg-accent/10 rounded-full blur-3xl group-hover:bg-accent/20 transition-colors" />
            <h2 className="text-sm font-bold text-secondary uppercase tracking-widest self-start mb-6 w-full">Clan Weekly Completion</h2>

            <div className="relative flex items-center justify-center w-48 h-48">
              <svg className="transform -rotate-90 w-48 h-48">
                <circle
                  cx="96" cy="96" r={circleRadius}
                  stroke="currentColor" strokeWidth="8" fill="transparent"
                  className="text-white/5"
                />
                <motion.circle
                  cx="96" cy="96" r={circleRadius}
                  stroke="currentColor" strokeWidth="8" fill="transparent"
                  strokeDasharray={circleCircumference}
                  initial={{ strokeDashoffset: circleCircumference }}
                  animate={{ strokeDashoffset }}
                  transition={{ duration: 1.5, ease: "easeOut" }}
                  className="text-accent shadow-[0_0_15px_rgba(168,85,247,0.5)]"
                  strokeLinecap="round"
                />
              </svg>
              <div className="absolute flex flex-col items-center justify-center">
                <span className="text-4xl font-black text-transparent bg-clip-text bg-gradient-to-r from-accent to-cyan-400">
                  {completionRate}%
                </span>
                <span className="text-[10px] text-tertiary uppercase font-bold tracking-widest mt-1">Average</span>
              </div>
            </div>

            <div className="w-full flex justify-between mt-6 text-sm border-t border-white/5 pt-4">
              <div className="text-center">
                <p className="text-green-400 font-bold">{activeCount}</p>
                <p className="text-tertiary text-[10px] uppercase font-bold">Active</p>
              </div>
              <div className="text-center border-l border-r border-white/5 px-4">
                <p className="text-secondary font-bold">{members.length - activeCount - warnedCount}</p>
                <p className="text-tertiary text-[10px] uppercase font-bold">Inactive</p>
              </div>
              <div className="text-center">
                <p className="text-red-400 font-bold">{warnedCount}</p>
                <p className="text-tertiary text-[10px] uppercase font-bold">Warned</p>
              </div>
            </div>
          </BaseCard>

          {/* Quick Actions */}
          <BaseCard className="p-5">
            <h2 className="text-sm font-bold text-secondary uppercase tracking-widest mb-4">Quick Actions</h2>
            <div className="grid grid-cols-2 gap-3">
              <button className="flex flex-col items-center gap-2 p-3 rounded-xl bg-white/[0.02] border border-white/5 hover:bg-white/10 hover:border-purple-500/30 transition-all text-xs font-bold text-primary">
                <FiFileText size={18} className="text-purple-400" /> Review Code
              </button>
              <button className="flex flex-col items-center gap-2 p-3 rounded-xl bg-white/[0.02] border border-white/5 hover:bg-white/10 hover:border-blue-500/30 transition-all text-xs font-bold text-primary">
                <FiMessageSquare size={18} className="text-blue-400" /> Clan Chat
              </button>
              <button className="flex flex-col items-center gap-2 p-3 rounded-xl bg-white/[0.02] border border-white/5 hover:bg-white/10 hover:border-yellow-500/30 transition-all text-xs font-bold text-primary">
                <FiAward size={18} className="text-yellow-400" /> Leaderboard
              </button>
              <button className="flex flex-col items-center gap-2 p-3 rounded-xl bg-white/[0.02] border border-white/5 hover:bg-white/10 hover:border-red-500/30 transition-all text-xs font-bold text-primary">
                <FiAlertTriangle size={18} className="text-red-400" /> Mass Warn
              </button>
            </div>
          </BaseCard>
        </div>

        {/* Right Col: Member Progress List */}
        <BaseCard className="p-6 xl:col-span-2 flex flex-col h-full">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-sm font-bold text-secondary uppercase tracking-widest flex items-center gap-2">
              <FiActivity className="text-accent" /> Member Progress Overview
            </h2>
            <button className="text-xs text-accent hover:text-accent-light transition-colors font-bold uppercase tracking-widest">View All</button>
          </div>

          <div className="space-y-3 flex-1 overflow-y-auto pr-2 custom-scrollbar">
            {members.slice(0, 6).map((member, i) => {
              const isActive = member.status !== 'Warned' && member.status !== 'Inactive';
              const isWarned = member.status === 'Warned';
              const solved = member.solvedProblems || 0;
              const total = TARGET_PROBLEMS;
              const progressPct = total > 0 ? Math.min(100, (solved / total) * 100) : 0;

              return (
                <div key={member._id} className={`flex items-center justify-between p-3 rounded-xl border transition-colors ${isWarned ? 'bg-red-500/10 border-red-500/20' : 'bg-white/[0.02] border-white/5 hover:bg-white/[0.04]'}`}>
                  <div className="flex items-center gap-3 w-1/3">
                    <div className="relative">
                      <div className="w-8 h-8 rounded-full bg-glass-surface flex items-center justify-center font-black text-xs text-primary">
                        {member.username[0].toUpperCase()}
                      </div>
                      <div className={`absolute -bottom-1 -right-1 w-3 h-3 rounded-full border-2 border-[#0f1115] ${isActive ? 'bg-green-500 animate-pulse' : 'bg-gray-500'}`} />
                    </div>
                    <div>
                      <p className="text-sm font-bold text-primary truncate max-w-[120px]">{member.username}</p>
                      <p className="text-[10px] uppercase font-bold text-tertiary">Active {isActive ? 'Now' : '2d ago'}</p>
                    </div>
                  </div>

                  <div className="flex-1 px-4 hidden md:block">
                    <div className="flex justify-between text-[10px] font-bold text-secondary mb-1">
                      <span>Set Progress</span>
                      <span>{solved}/{total}</span>
                    </div>
                    <div className="h-1.5 w-full bg-black/40 rounded-full overflow-hidden">
                      <motion.div 
                        initial={{ width: 0 }} animate={{ width: `${progressPct}%` }}
                        className={`h-full ${progressPct === 100 ? 'bg-green-400' : 'bg-accent'}`}
                      />
                    </div>
                  </div>

                  <div className="flex items-center gap-4 w-1/4 justify-end">
                    <div className="text-right hidden sm:block">
                      <p className="text-xs font-black text-primary">{member.codingLevel || 'Beginner'}</p>
                      <p className="text-[10px] text-yellow-400 flex items-center justify-end gap-1"><FiAward/> {(member.points || 0)} XP</p>
                    </div>
                    <button 
                      onClick={() => setWarningModal({ open: true, user: member, message: '' })}
                      className="p-2 rounded-lg bg-red-500/10 text-red-400 hover:bg-red-500/20 transition-colors"
                      title="Issue Warning"
                    >
                      <FiAlertTriangle size={14} />
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        </BaseCard>
      </div>

      {/* Join Requests */}
      <BaseCard className="p-6 space-y-4">
        <h2 className="text-sm font-bold text-secondary uppercase tracking-widest flex items-center gap-2">
          <FiShield className="text-blue-400" /> Pending Join Requests ({clan.requests?.length || 0})
        </h2>
        {clan.requests?.length === 0 ? (
          <p className="text-tertiary text-sm py-4">No pending requests.</p>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {clan.requests?.map((reqUser) => (
              <div key={reqUser._id} className="flex items-center justify-between p-4 rounded-xl bg-white/[0.02] border border-white/5">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-blue-500/20 text-blue-400 flex items-center justify-center font-black">
                    {reqUser.username[0].toUpperCase()}
                  </div>
                  <div>
                    <p className="text-sm font-bold text-primary">{reqUser.username}</p>
                    <p className="text-xs text-secondary">{reqUser.email}</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => approveMutation.mutate(reqUser._id)} className="w-8 h-8 rounded-lg bg-green-500/20 text-green-400 flex items-center justify-center hover:bg-green-500/30 transition-colors">
                    <FiCheck />
                  </button>
                  <button onClick={() => rejectMutation.mutate(reqUser._id)} className="w-8 h-8 rounded-lg bg-red-500/20 text-red-400 flex items-center justify-center hover:bg-red-500/30 transition-colors">
                    <FiX />
                  </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </BaseCard>

      {/* Warning Modal */}
      <AnimatePresence>
        {warningModal.open && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
            <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className="w-full max-w-md">
              <BaseCard className="p-6 border-red-500/30 space-y-4">
                <div className="flex justify-between items-start">
                  <div>
                    <h3 className="text-lg font-black text-red-400 flex items-center gap-2"><FiAlertTriangle /> Issue Warning</h3>
                    <p className="text-xs text-secondary mt-1">Send an official warning to {warningModal.user?.username}.</p>
                  </div>
                  <button onClick={() => setWarningModal({ open: false, user: null, message: '' })} className="text-tertiary hover:text-white"><FiX size={20}/></button>
                </div>
                <textarea
                  className="field-textarea"
                  rows="4"
                  placeholder="Reason for warning (sent via email)..."
                  value={warningModal.message}
                  onChange={e => setWarningModal({ ...warningModal, message: e.target.value })}
                />
                <div className="flex justify-end gap-3 pt-4">
                  <button onClick={() => setWarningModal({ open: false, user: null, message: '' })} className="px-4 py-2 text-sm font-bold text-secondary hover:text-primary">Cancel</button>
                  <button 
                    onClick={() => warnMutation.mutate({ userId: warningModal.user._id, message: warningModal.message })}
                    disabled={warnMutation.isLoading}
                    className="btn-primary bg-red-500 hover:bg-red-600 text-white shadow-lg shadow-red-500/20 border-0"
                  >
                    {warnMutation.isLoading ? 'Sending...' : 'Issue Warning'}
                  </button>
                </div>
              </BaseCard>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

    </div>
  );
};

export default ChiefDashboardTab;

import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import toast from 'react-hot-toast';
import { motion, AnimatePresence } from 'framer-motion';
import { FiUsers, FiSearch, FiAlertTriangle, FiX, FiAward, FiEdit2 } from 'react-icons/fi';
import BaseCard from '../../components/BaseCard';
import MemberHoverCard from '../../components/MemberHoverCard';
import { api } from '../../lib/api';

const ChiefMembersTab = ({ clan }) => {
  const queryClient = useQueryClient();
  const [levelModal, setLevelModal] = useState({ open: false, user: null });
  const [warnModal, setWarnModal] = useState({ open: false, user: null });
  const [selectedLevel, setSelectedLevel] = useState('');
  const [warnMessage, setWarnMessage] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');

  const levelMutation = useMutation({
    mutationFn: async ({ userId, level }) => {
      const res = await api.put(`/api/users/${userId}/level`, { level });
      return res.data;
    },
    onSuccess: () => {
      toast.success('Member level updated');
      queryClient.invalidateQueries(['chief-clan-info']);
      setLevelModal({ open: false, user: null });
    }
  });

  const warnMutation = useMutation({
    mutationFn: async ({ userId, message }) => {
      const res = await api.post(`/api/users/${userId}/warn`, { message });
      return res.data;
    },
    onSuccess: () => {
      toast.success('Warning sent to member via email');
      queryClient.invalidateQueries(['chief-clan-info']);
      setWarnModal({ open: false, user: null });
      setWarnMessage('');
    },
    onError: (err) => {
      toast.error(err?.response?.data?.message || 'Failed to send warning');
    }
  });

  if (!clan) return null;

  const members = clan.members || [];

  const filteredMembers = members.filter(member => {
    const matchesSearch = member.username.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          (member.regNo && member.regNo.toLowerCase().includes(searchTerm.toLowerCase()));
    const memberStatus = member.status || 'Active';
    if (statusFilter === 'All') return matchesSearch;
    return matchesSearch && memberStatus === statusFilter;
  });

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <h2 className="text-section-title font-bold flex items-center gap-2">
          <FiUsers className="text-blue-400" /> Member Management
        </h2>
        <div className="flex items-center gap-3 w-full md:w-auto">
          <div className="relative w-full md:w-64">
            <FiSearch className="absolute left-3 top-1/2 -translate-y-1/2 text-tertiary" />
            <input 
              type="text" 
              placeholder="Search by name or reg no..." 
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              className="field-input pl-10 h-10 text-sm w-full"
            />
          </div>
          <select 
            value={statusFilter} 
            onChange={e => setStatusFilter(e.target.value)}
            className="field-select h-10 text-sm"
          >
            <option value="All">All Status</option>
            <option value="Active">Active</option>
            <option value="Inactive">Inactive</option>
            <option value="Warned">Warned</option>
          </select>
        </div>
      </div>

      <BaseCard className="p-0 overflow-hidden overflow-x-auto">
        <table className="w-full text-left border-collapse min-w-[800px]">
          <thead>
            <tr className="bg-white/[0.02] border-b border-white/[0.05] text-xs uppercase tracking-widest text-tertiary font-bold">
              <th className="p-4 pl-6">Member</th>
              <th className="p-4">Reg No</th>
              <th className="p-4">Level</th>
              <th className="p-4">Solved</th>
              <th className="p-4">Stats</th>
              <th className="p-4">Status</th>
              <th className="p-4 text-right pr-6">Action</th>
            </tr>
          </thead>
          <tbody>
            {filteredMembers.map((user, i) => {
              const isWarned = user.status === 'Warned';
              const isInactive = user.status === 'Inactive';
              const isActive = !isWarned && !isInactive;
              const solved = user.solvedProblems || 0;

              return (
                <motion.tr 
                  key={user._id} 
                  initial={{ opacity: 0, y: 5 }} 
                  animate={{ opacity: 1, y: 0 }} 
                  transition={{ delay: i * 0.05 }} 
                  className={`border-b border-white/[0.02] transition-colors ${isWarned ? 'bg-red-500/[0.05] hover:bg-red-500/10' : 'hover:bg-white/[0.02]'}`}
                >
                  <td className="p-4 pl-6 font-bold text-sm text-primary flex items-center gap-3">
                    <div className="relative">
                      <div className="w-10 h-10 rounded-xl bg-glass-surface flex items-center justify-center font-black text-blue-400">
                        {user.username[0].toUpperCase()}
                      </div>
                      <div className={`absolute -bottom-1 -right-1 w-3 h-3 rounded-full border-2 border-[#0f1115] ${isActive ? 'bg-green-500 animate-pulse' : isWarned ? 'bg-red-500' : 'bg-gray-500'}`} />
                    </div>
                    <div>
                      {/* MemberHoverCard replaces ProfilePopover — click opens full profile */}
                      <MemberHoverCard userId={user._id} username={user.username}>
                        <span className="cursor-pointer hover:text-blue-400 transition-colors block">{user.username}</span>
                      </MemberHoverCard>
                      <span className="text-[10px] text-tertiary uppercase">{user.email}</span>
                    </div>
                  </td>
                  <td className="p-4 text-sm text-secondary font-mono">{user.regNo || 'N/A'}</td>
                  <td className="p-4 text-sm">
                    <button 
                      onClick={() => { setLevelModal({ open: true, user }); setSelectedLevel(user.codingLevel || 'Beginner'); }}
                      className="group relative inline-flex items-center gap-1.5 px-3 py-1 rounded bg-white/5 hover:bg-white/10 text-xs font-bold text-tertiary hover:text-white border border-white/10 transition-all uppercase tracking-widest"
                      title="Click to change level"
                    >
                      {user.codingLevel || 'Beginner'}
                      <FiEdit2 size={10} className="opacity-0 group-hover:opacity-100 transition-opacity" />
                    </button>
                  </td>
                  <td className="p-4 text-sm text-secondary font-mono font-bold">{solved} solved</td>
                  <td className="p-4 text-xs font-bold">
                    <div className="flex flex-col gap-1 text-secondary">
                      <span className="flex items-center gap-1 text-yellow-400"><FiAward size={12}/> {user.points || 0} XP</span>
                      <span>🔥 {user.streak || 0} days</span>
                    </div>
                  </td>
                  <td className="p-4 text-sm">
                    {isWarned ? (
                      <span className="px-2 py-1 rounded-md bg-red-500/20 text-red-400 text-[10px] font-black uppercase tracking-widest">Warned</span>
                    ) : isActive ? (
                      <span className="px-2 py-1 rounded-md bg-green-500/20 text-green-400 text-[10px] font-black uppercase tracking-widest">Active</span>
                    ) : (
                      <span className="px-2 py-1 rounded-md bg-white/10 text-tertiary text-[10px] font-black uppercase tracking-widest">Inactive</span>
                    )}
                  </td>
                  <td className="p-4 text-right pr-6">
                    <button 
                      onClick={() => setWarnModal({ open: true, user })}
                      className={`p-2 rounded-lg text-xs font-bold transition-colors inline-flex items-center gap-2 ${isWarned ? 'bg-red-500/10 text-red-500 hover:bg-red-500/20' : 'bg-white/5 text-secondary hover:text-red-400 hover:bg-red-500/10'}`}
                      title="Issue Warning"
                    >
                      <FiAlertTriangle /> {isWarned ? 'Warn Again' : 'Warn'}
                    </button>
                  </td>
                </motion.tr>
              );
            })}
            {filteredMembers.length === 0 && (
              <tr>
                <td colSpan="7" className="p-8 text-center text-tertiary text-sm">
                  No members found matching your filters.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </BaseCard>

      {/* Level Change Modal */}
      <AnimatePresence>
        {levelModal.open && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className="w-full max-w-sm">
              <BaseCard className="p-6 space-y-6">
                <div className="flex justify-between items-center">
                  <h3 className="text-lg font-black text-primary">Update Level</h3>
                  <button onClick={() => setLevelModal({ open: false, user: null })} className="text-tertiary hover:text-primary"><FiX size={20} /></button>
                </div>
                <div>
                  <p className="text-sm text-secondary mb-4">Select new level for <strong className="text-white">{levelModal.user.username}</strong>:</p>
                  <select className="field-select w-full" value={selectedLevel} onChange={e => setSelectedLevel(e.target.value)}>
                    <option value="Beginner">Beginner</option>
                    <option value="Intermediate">Intermediate</option>
                    <option value="Advanced">Advanced</option>
                  </select>
                </div>
                <div className="flex justify-end gap-3">
                  <button onClick={() => setLevelModal({ open: false, user: null })} className="px-4 py-2 text-sm text-secondary hover:text-white">Cancel</button>
                  <button 
                    onClick={() => levelMutation.mutate({ userId: levelModal.user._id, level: selectedLevel })}
                    disabled={levelMutation.isPending}
                    className="btn-primary px-4 py-2 text-sm"
                  >
                    {levelMutation.isPending ? 'Saving...' : 'Save Changes'}
                  </button>
                </div>
              </BaseCard>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      {/* Warning Modal */}
      <AnimatePresence>
        {warnModal.open && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className="w-full max-w-md">
              <BaseCard className="p-6 space-y-6 border border-red-500/30">
                <div className="flex justify-between items-center">
                  <h3 className="text-lg font-black text-red-400 flex items-center gap-2"><FiAlertTriangle /> Issue Warning</h3>
                  <button onClick={() => setWarnModal({ open: false, user: null })} className="text-tertiary hover:text-primary"><FiX size={20} /></button>
                </div>
                <div>
                  <p className="text-sm text-secondary mb-4">This will send an official warning email to <strong className="text-white">{warnModal.user.username}</strong> ({warnModal.user.email}) and flag their status.</p>
                  <textarea 
                    className="field-textarea text-sm" 
                    rows="3" 
                    placeholder="Reason for warning..."
                    value={warnMessage}
                    onChange={e => setWarnMessage(e.target.value)}
                  />
                </div>
                <div className="flex justify-end gap-3">
                  <button onClick={() => setWarnModal({ open: false, user: null })} className="px-4 py-2 text-sm text-secondary hover:text-white">Cancel</button>
                  <button 
                    onClick={() => warnMutation.mutate({ userId: warnModal.user._id, message: warnMessage })}
                    disabled={warnMutation.isPending || !warnMessage}
                    className="btn-primary px-4 py-2 text-sm !bg-red-500 hover:!bg-red-600 shadow-[0_0_15px_rgba(239,68,68,0.3)]"
                  >
                    {warnMutation.isPending ? 'Sending...' : 'Send Warning Email'}
                  </button>
                </div>
              </BaseCard>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

    </div>
  );
};

export default ChiefMembersTab;

import React, { useState } from 'react';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import toast from 'react-hot-toast';
import { motion, AnimatePresence } from 'framer-motion';
import { FiPlus, FiTrash2, FiMessageSquare, FiX } from 'react-icons/fi';
import BaseCard from '../../components/BaseCard';
import { api } from '../../lib/api';

const ChiefNoticeTab = ({ clan }) => {
  const queryClient = useQueryClient();
  const [createModal, setCreateModal] = useState(false);
  const [noticeText, setNoticeText] = useState('');

  const createMutation = useMutation({
    mutationFn: async (notice) => {
      const res = await api.post(`/api/clans/${clan._id}/notices`, { notice });
      return res.data;
    },
    onSuccess: () => {
      toast.success('Notice posted to clan');
      queryClient.invalidateQueries(['chief-clan-info']);
      setCreateModal(false);
      setNoticeText('');
    }
  });

  const deleteMutation = useMutation({
    mutationFn: async (index) => {
      const res = await api.delete(`/api/clans/${clan._id}/notices/${index}`);
      return res.data;
    },
    onSuccess: () => {
      toast.success('Notice removed');
      queryClient.invalidateQueries(['chief-clan-info']);
    }
  });

  if (!clan) return null;

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-section-title font-bold flex items-center gap-2">
          <FiMessageSquare className="text-blue-400" /> Internal Clan Notices
        </h2>
        <button onClick={() => setCreateModal(true)} className="btn-primary py-2 px-4 text-sm flex items-center gap-2">
          <FiPlus /> Post Notice
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {clan.notices?.map((notice, i) => (
          <motion.div key={i} initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} transition={{ delay: i * 0.05 }}>
            <BaseCard className="p-5 flex flex-col gap-3 group relative overflow-hidden border-l-4 border-blue-500">
              <div className="flex justify-between items-start pr-8">
                <p className="text-primary leading-relaxed text-sm">{notice}</p>
                <button 
                  onClick={() => { if(window.confirm('Delete this notice?')) deleteMutation.mutate(i); }} 
                  className="absolute top-4 right-4 text-red-400 hover:text-red-300 p-1 opacity-0 group-hover:opacity-100 transition-opacity bg-red-500/10 rounded-lg"
                >
                  <FiTrash2 size={16} />
                </button>
              </div>
            </BaseCard>
          </motion.div>
        ))}
        {(!clan.notices || clan.notices.length === 0) && (
          <div className="md:col-span-2 text-center py-10 text-tertiary">No internal clan notices posted.</div>
        )}
      </div>

      <AnimatePresence>
        {createModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className="w-full max-w-md">
              <BaseCard className="p-6 space-y-6">
                <div className="flex justify-between items-center">
                  <h3 className="text-lg font-black text-primary">Post Clan Notice</h3>
                  <button onClick={() => setCreateModal(false)} className="text-tertiary hover:text-primary"><FiX size={20} /></button>
                </div>

                <div>
                  <textarea 
                    className="field-textarea text-sm" 
                    rows="4" 
                    placeholder="Enter message for your clan members..."
                    value={noticeText}
                    onChange={e => setNoticeText(e.target.value)}
                  />
                  <p className="text-[10px] text-tertiary mt-2">This will only be visible to members of {clan.name}.</p>
                </div>

                <div className="flex gap-3 justify-end">
                  <button onClick={() => setCreateModal(false)} className="px-4 py-2 rounded-xl font-bold text-sm bg-white/5 text-secondary hover:bg-white/10 transition-colors">Cancel</button>
                  <button 
                    onClick={() => createMutation.mutate(noticeText)} 
                    disabled={createMutation.isLoading || !noticeText.trim()} 
                    className="btn-primary px-6 py-2 text-sm"
                  >
                    {createMutation.isLoading ? 'Posting...' : 'Post Notice'}
                  </button>
                </div>
              </BaseCard>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default ChiefNoticeTab;

import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import toast from 'react-hot-toast';
import { motion } from 'framer-motion';
import { FiCheck, FiX, FiCode, FiEye, FiCpu, FiFilter, FiExternalLink } from 'react-icons/fi';
import BaseCard from '../../components/BaseCard';
import { api } from '../../lib/api';

const ChiefReviewTab = ({ clan }) => {
  const queryClient = useQueryClient();
  const [statusFilter, setStatusFilter] = useState('Pending');

  const submissionsQuery = useQuery({
    queryKey: ['chief-submissions', clan?._id, statusFilter],
    queryFn: async () => {
      const params = new URLSearchParams();
      params.set('page', '1');
      params.set('limit', '50');
      if (statusFilter !== 'All') {
        const apiStatus = statusFilter === 'Approved' ? 'Accepted' : statusFilter;
        params.set('status', apiStatus);
      }
      const res = await api.get(`/api/submissions?${params.toString()}`);
      const allSubs = res.data.data || [];
      // Filter to only show submissions from clan members
      return allSubs.filter(sub =>
        clan.members.some(m => {
          const memberId = typeof m === 'object' ? m._id : m;
          const subUserId = typeof sub.userId === 'object' ? sub.userId._id : sub.userId;
          return memberId?.toString() === subUserId?.toString();
        })
      );
    },
    enabled: !!clan
  });

  const gradeMutation = useMutation({
    mutationFn: async ({ id, status, feedback }) => {
      const res = await api.put(`/api/submissions/${id}`, { status, feedback: feedback || undefined });
      return res.data;
    },
    onSuccess: () => {
      toast.success('Submission graded');
      queryClient.invalidateQueries({ queryKey: ['chief-submissions'] });
    }
  });

  if (!clan) return null;

  const filteredSubs = submissionsQuery.data || [];
  const pendingCount = filteredSubs.filter(s => s.status === 'Pending').length;

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <h2 className="text-section-title font-bold flex items-center gap-2">
          <FiCode className="text-purple-400" /> Code Reviews
        </h2>

        <div className="flex items-center gap-2 bg-white/5 p-1 rounded-xl border border-white/10">
          <FiFilter className="text-tertiary ml-2" />
          {['Pending', 'Approved', 'Rejected', 'All'].map(filter => (
            <button
              key={filter}
              onClick={() => setStatusFilter(filter)}
              className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${statusFilter === filter ? 'bg-purple-500/20 text-purple-400 shadow-[0_0_10px_rgba(168,85,247,0.2)]' : 'text-secondary hover:text-primary hover:bg-white/5'}`}
            >
              {filter} {filter === 'Pending' && pendingCount > 0 && `(${pendingCount})`}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
        {filteredSubs.map((sub, i) => (
          <motion.div key={sub._id} initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} transition={{ delay: i * 0.05 }}>
            <BaseCard className="p-5 flex flex-col gap-4 group hover:border-purple-500/30 transition-colors h-full">
              <div className="flex justify-between items-start">
                <div className="min-w-0 flex-1">
                  <Link 
                    to={`/challenge/${sub.challengeId?._id}?review=${sub._id}`}
                    className="font-bold text-primary truncate block hover:text-accent transition-colors"
                  >
                    {sub.challengeId?.title || 'Unknown Challenge'}
                  </Link>
                  <p className="text-xs text-secondary mt-1">By: {sub.userId?.username}</p>
                </div>
                {sub.status === 'Pending' && <span className="bg-purple-500/20 text-purple-400 border border-purple-500/30 px-2 py-1 rounded text-[10px] font-black uppercase tracking-widest shrink-0 ml-2">Needs Review</span>}
                {sub.status === 'Accepted' && <span className="bg-green-500/20 text-green-400 border border-green-500/30 px-2 py-1 rounded text-[10px] font-black uppercase tracking-widest shrink-0 ml-2">Approved</span>}
                {sub.status === 'Rejected' && <span className="bg-red-500/20 text-red-400 border border-red-500/30 px-2 py-1 rounded text-[10px] font-black uppercase tracking-widest shrink-0 ml-2">Rejected</span>}
              </div>

              {/* Language & Info */}
              <div className="flex items-center gap-3 p-3 rounded-lg bg-white/[0.02] border border-white/[0.05]">
                <div className="flex-1">
                  <div className="flex justify-between text-[10px] font-bold text-tertiary mb-1 uppercase tracking-widest">
                    <span>{sub.language || 'javascript'}</span>
                    <span className="text-secondary">{sub.code ? `${sub.code.split('\n').length} lines` : 'Repo only'}</span>
                  </div>
                </div>
                <FiCode className="text-tertiary" />
              </div>

              <div className="flex justify-between items-center mt-auto pt-2">
                <span className="text-xs font-mono text-tertiary">{new Date(sub.submittedAt).toLocaleString()}</span>
                <Link 
                  to={`/challenge/${sub.challengeId?._id}?review=${sub._id}`}
                  className="px-4 py-2 rounded-lg bg-white/5 text-primary text-xs font-bold hover:bg-white/10 transition-colors flex items-center gap-2"
                >
                  <FiEye /> Review Code
                </Link>
              </div>

              {/* Feedback display for already reviewed */}
              {sub.feedback && (
                <div className="mt-1 p-2 rounded-lg bg-white/[0.02] border border-white/[0.05] text-xs text-secondary italic">
                  "{sub.feedback}"
                </div>
              )}
            </BaseCard>
          </motion.div>
        ))}
        {filteredSubs.length === 0 && (
          <div className="xl:col-span-3 p-10 text-center border-2 border-dashed border-white/10 rounded-2xl text-tertiary">
            <FiCheck size={48} className="mx-auto mb-4 text-green-400/50" />
            <p>No {statusFilter.toLowerCase()} submissions found.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default ChiefReviewTab;

import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import toast from 'react-hot-toast';
import { motion, AnimatePresence } from 'framer-motion';
import { FiUsers, FiUserPlus, FiPercent, FiX, FiShield, FiArrowLeft, FiTrash2, FiAward, FiPlus, FiUserMinus } from 'react-icons/fi';
import BaseCard from '../../components/BaseCard';
import MemberHoverCard from '../../components/MemberHoverCard';
import { api } from '../../lib/api';

const ClanManagerTab = () => {
  const queryClient = useQueryClient();
  const [assignModal, setAssignModal] = useState({ open: false, user: null });
  const [selectedClanForAssign, setSelectedClanForAssign] = useState('');
  const [viewClanId, setViewClanId] = useState(null);
  const [createModal, setCreateModal] = useState({ open: false, name: '', tag: '', description: '' });

  const clansQuery = useQuery({
    queryKey: ['admin-clans'],
    queryFn: async () => {
      const res = await api.get('/api/clans/leaderboard');
      return res.data.data || [];
    }
  });

  const clanDetailQuery = useQuery({
    queryKey: ['admin-clan-detail', viewClanId],
    queryFn: async () => {
      const res = await api.get(`/api/clans/${viewClanId}/admin-stats`);
      return res.data.data;
    },
    enabled: !!viewClanId
  });

  const unassignedQuery = useQuery({
    queryKey: ['admin-unassigned-users'],
    queryFn: async () => {
      const res = await api.get('/api/users');
      // Filter out users who already have a clan
      return (res.data.data || []).filter(u => !u.clan && u.role === 'user');
    }
  });

  const createMutation = useMutation({
    mutationFn: async (newClan) => {
      const res = await api.post('/api/clans', newClan);
      return res.data;
    },
    onSuccess: () => {
      toast.success('Clan created successfully!');
      queryClient.invalidateQueries(['admin-clans']);
      setCreateModal({ open: false, name: '', tag: '', description: '' });
    },
    onError: (err) => {
      toast.error(err.response?.data?.message || 'Failed to create clan');
    }
  });

  const assignMutation = useMutation({
    mutationFn: async ({ clanId, userId }) => {
      const res = await api.post(`/api/clans/${clanId}/members`, { userId });
      return res.data;
    },
    onSuccess: () => {
      toast.success('Member assigned successfully!');
      queryClient.invalidateQueries(['admin-clans']);
      queryClient.invalidateQueries(['admin-unassigned-users']);
      if (viewClanId) queryClient.invalidateQueries(['admin-clan-detail', viewClanId]);
      setAssignModal({ open: false, user: null });
      setSelectedClanForAssign('');
    },
    onError: (err) => {
      toast.error(err.response?.data?.message || 'Failed to assign member');
    }
  });

  const handleAssign = () => {
    if (!selectedClanForAssign) {
      toast.error('Please select a clan');
      return;
    }
    assignMutation.mutate({ clanId: selectedClanForAssign, userId: assignModal.user._id });
  };

  const removeMemberMutation = useMutation({
    mutationFn: async ({ clanId, userId }) => {
      const res = await api.delete(`/api/clans/${clanId}/members/${userId}`);
      return res.data;
    },
    onSuccess: () => {
      toast.success('Member removed from clan');
      queryClient.invalidateQueries(['admin-clan-detail', viewClanId]);
      queryClient.invalidateQueries(['admin-clans']);
      queryClient.invalidateQueries(['admin-unassigned-users']);
    },
    onError: (err) => {
      toast.error(err.response?.data?.message || 'Failed to remove member');
    }
  });

  const updateRoleMutation = useMutation({
    mutationFn: async ({ userId, role }) => {
      return api.put(`/api/users/${userId}/role`, { role });
    },
    onSuccess: () => {
      toast.success("Role updated");
      queryClient.invalidateQueries(['admin-clan-detail', viewClanId]);
      queryClient.invalidateQueries(['admin-clans']);
    },
    onError: () => {
      toast.error("Failed to update role");
    }
  });

  if (viewClanId) {
    const clan = clanDetailQuery.data;
    return (
      <motion.div initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }} className="space-y-6">
        <button onClick={() => setViewClanId(null)} className="flex items-center gap-2 text-tertiary hover:text-primary transition-colors text-sm font-bold bg-white/5 px-4 py-2 rounded-xl w-fit">
          <FiArrowLeft /> Back to Clan Overview
        </button>

        {clanDetailQuery.isLoading ? (
          <div className="flex justify-center p-12"><div className="w-8 h-8 border-2 border-accent border-t-transparent rounded-full animate-spin" /></div>
        ) : clan ? (
          <>
            <BaseCard className="p-6 relative overflow-hidden group">
              <div className="absolute right-0 top-0 w-64 h-64 bg-accent/5 rounded-full blur-3xl" />
              <div className="relative z-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
                <div>
                  <h2 className="text-3xl font-black text-primary flex items-center gap-3">
                    {clan.name}
                    <span className="px-3 py-1 bg-white/5 border border-white/10 rounded-full text-xs text-tertiary font-mono tracking-widest uppercase">{clan.tag}</span>
                  </h2>
                  <p className="text-secondary mt-2">{clan.description}</p>
                  <div className="text-sm text-tertiary mt-2 flex items-center gap-2">
                    <FiShield className="text-accent" /> Chief: 
                    {clan.chief ? (
                       <MemberHoverCard userId={clan.chief._id} username={clan.chief.username}>
                          <strong className="text-primary hover:text-accent transition-colors cursor-pointer">{clan.chief.username}</strong>
                       </MemberHoverCard>
                    ) : (
                       <strong className="text-primary">Unassigned</strong>
                    )}
                  </div>
                </div>
                <div className="flex gap-4">
                  <div className="text-center bg-white/5 px-6 py-3 rounded-xl border border-white/10">
                    <p className="text-2xl font-black text-blue-400">{clan.members?.length || 0}</p>
                    <p className="text-[10px] text-tertiary uppercase font-bold tracking-widest">Members</p>
                  </div>
                  <div className="text-center bg-white/5 px-6 py-3 rounded-xl border border-white/10">
                    <p className="text-2xl font-black text-green-400">
                      {clan.members?.reduce((acc, m) => acc + (m.solvedCount || 0), 0) || 0}
                    </p>
                    <p className="text-[10px] text-tertiary uppercase font-bold tracking-widest">Total Solved</p>
                  </div>
                  <div className="text-center bg-white/5 px-6 py-3 rounded-xl border border-white/10">
                    <p className="text-2xl font-black text-purple-400">
                      {clan.members?.reduce((acc, m) => acc + (m.points || 0), 0) || 0}
                    </p>
                    <p className="text-[10px] text-tertiary uppercase font-bold tracking-widest">Total Points</p>
                  </div>
                </div>
              </div>
            </BaseCard>

            <h3 className="text-xl font-bold flex items-center gap-2 text-primary mt-8"><FiUsers className="text-blue-400" /> Clan Roster & Progress</h3>
            <BaseCard className="p-0 overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left border-collapse whitespace-nowrap">
                  <thead>
                    <tr className="bg-white/[0.02] border-b border-white/[0.05] text-xs uppercase tracking-widest text-tertiary font-bold">
                      <th className="p-4">Member</th>
                      <th className="p-4">Reg No</th>
                      <th className="p-4">Coding Level</th>
                      <th className="p-4">Points</th>
                      <th className="p-4">Solved</th>
                      <th className="p-4 text-right">Action</th>
                    </tr>
                  </thead>
                  <tbody>
                    {clan.members?.map(member => (
                      <tr key={member._id} className="border-b border-white/[0.02] hover:bg-white/[0.01] transition-colors">
                        <td className="p-4 flex items-center gap-3">
                          <div className="w-8 h-8 rounded-full bg-accent/20 text-accent flex items-center justify-center font-black">
                            {member.username[0].toUpperCase()}
                          </div>
                          <div>
                            <p className="font-bold text-sm text-primary flex items-center gap-2">
                              <MemberHoverCard userId={member._id} username={member.username}>
                                <span className="hover:text-accent transition-colors cursor-pointer">{member.username}</span>
                              </MemberHoverCard>
                              {clan.chief?._id === member._id && <FiAward className="text-yellow-400" title="Clan Chief" />}
                            </p>
                            <p className="text-xs text-tertiary">{member.email}</p>
                          </div>
                        </td>
                        <td className="p-4 text-sm text-secondary font-mono">{member.regNo || 'N/A'}</td>
                        <td className="p-4">
                          <span className="px-2 py-1 rounded bg-white/5 text-[10px] font-bold text-tertiary border border-white/10 uppercase tracking-widest">
                            {member.codingLevel || 'Beginner'}
                          </span>
                        </td>
                        <td className="p-4 text-sm font-bold text-purple-400">{member.points || 0}</td>
                        <td className="p-4 text-sm font-bold text-green-400">{member.solvedCount || 0}</td>
                        <td className="p-4 flex items-center justify-end gap-2">
                          {clan.chief?._id !== member._id ? (
                            <button 
                              onClick={() => {
                                if (window.confirm(`Make ${member.username} the Clan Chief?`)) {
                                  updateRoleMutation.mutate({ userId: member._id, role: 'clan-chief' });
                                }
                              }}
                              className="p-2 rounded-lg bg-blue-500/10 text-blue-400 hover:bg-blue-500/20 transition-colors"
                              title="Make Clan Chief"
                            >
                              <FiShield size={14} />
                            </button>
                          ) : (
                            <button 
                              onClick={() => {
                                if (window.confirm(`Demote ${member.username} to regular member?`)) {
                                  updateRoleMutation.mutate({ userId: member._id, role: 'member' });
                                }
                              }}
                              className="p-2 rounded-lg bg-yellow-500/10 text-yellow-400 hover:bg-yellow-500/20 transition-colors"
                              title="Demote to Member"
                            >
                              <FiUserMinus size={14} />
                            </button>
                          )}
                          <button 
                            onClick={() => {
                              if (window.confirm(`Remove ${member.username} from clan?`)) {
                                removeMemberMutation.mutate({ clanId: clan._id, userId: member._id });
                              }
                            }} 
                            className="p-2 rounded-lg bg-red-500/10 text-red-400 hover:bg-red-500/20 transition-colors"
                            title="Remove Member"
                          >
                            <FiTrash2 size={14} />
                          </button>
                        </td>
                      </tr>
                    ))}
                    {(!clan.members || clan.members.length === 0) && (
                      <tr><td colSpan="6" className="p-8 text-center text-tertiary text-sm">No members in this clan.</td></tr>
                    )}
                  </tbody>
                </table>
              </div>
            </BaseCard>
          </>
        ) : (
          <div className="p-8 text-center text-red-400">Failed to load clan details.</div>
        )}
      </motion.div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Clan Cards Grid */}
      <div className="flex flex-col sm:flex-row justify-between sm:items-center gap-4">
         <h2 className="text-section-title font-bold flex items-center gap-2"><FiShield className="text-accent" /> Clan Overview</h2>
         <button onClick={() => setCreateModal({ ...createModal, open: true })} className="btn-primary flex items-center justify-center gap-2 px-4 py-2 text-sm w-full sm:w-auto">
            <FiPlus /> Create Clan
         </button>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-4">
        {clansQuery.data?.map((clan, i) => (
          <motion.div key={clan._id} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.1 }}>
            <BaseCard 
              className="p-5 flex flex-col gap-4 relative overflow-hidden group cursor-pointer hover:border-accent/50 transition-colors"
              onClick={() => setViewClanId(clan._id)}
            >
              <div className="absolute -right-8 -top-8 w-24 h-24 bg-accent/10 rounded-full blur-2xl group-hover:bg-accent/20 transition-colors" />

              <div>
                <h3 className="font-bold text-xl text-primary group-hover:text-accent transition-colors">{clan.name}</h3>
                <div className="text-xs text-tertiary uppercase tracking-widest mt-1 flex items-center gap-1">
                   Chief: 
                   <span className="text-secondary font-bold">
                      {clan.chief ? (
                        <MemberHoverCard userId={clan.chief._id} username={clan.chief.username}>
                           <span className="hover:text-accent transition-colors">{clan.chief.username}</span>
                        </MemberHoverCard>
                      ) : 'None'}
                   </span>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-2 text-center my-2">
                <div className="bg-white/[0.03] rounded-lg p-2 border border-white/[0.05]">
                  <p className="text-lg font-black text-blue-400">{clan.memberCount}</p>
                  <p className="text-[9px] text-tertiary uppercase font-bold"><FiUsers className="inline mr-1"/>Members</p>
                </div>
                <div className="bg-white/[0.03] rounded-lg p-2 border border-white/[0.05]">
                  <p className="text-lg font-black text-green-400">{clan.solvedCount}</p>
                  <p className="text-[9px] text-tertiary uppercase font-bold"><FiPercent className="inline mr-1"/>Solved</p>
                </div>
              </div>
            </BaseCard>
          </motion.div>
        ))}
      </div>

      {/* Unassigned Members Table */}
      <div className="mt-8">
        <h2 className="text-section-title font-bold flex items-center gap-2 mb-4"><FiUsers className="text-orange-400" /> Unassigned Recruits</h2>
        <BaseCard className="p-0 overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse whitespace-nowrap">
              <thead>
                <tr className="bg-white/[0.02] border-b border-white/[0.05] text-xs uppercase tracking-widest text-tertiary font-bold">
                  <th className="p-4">Recruit</th>
                  <th className="p-4">Reg No</th>
                  <th className="p-4">Branch/Year</th>
                  <th className="p-4">Level</th>
                  <th className="p-4 text-right">Action</th>
                </tr>
              </thead>
              <tbody>
                {unassignedQuery.data?.map(user => (
                  <tr key={user._id} className="border-b border-white/[0.02] hover:bg-white/[0.01] transition-colors">
                    <td className="p-4 font-bold text-sm text-primary flex items-center gap-3">
                      <div className="w-8 h-8 rounded-full bg-accent/20 text-accent flex items-center justify-center font-black">{user.username[0].toUpperCase()}</div>
                      <MemberHoverCard userId={user._id} username={user.username}>
                        <span className="hover:text-accent transition-colors cursor-pointer">{user.username}</span>
                      </MemberHoverCard>
                    </td>
                    <td className="p-4 text-sm text-secondary font-mono">{user.regNo || 'N/A'}</td>
                    <td className="p-4 text-sm text-secondary">{user.branch} / {user.year}</td>
                    <td className="p-4">
                      <span className="px-2 py-1 rounded bg-white/5 text-[10px] font-bold text-tertiary border border-white/10 uppercase tracking-widest">
                        {user.codingLevel}
                      </span>
                    </td>
                    <td className="p-4 text-right">
                      <button onClick={() => setAssignModal({ open: true, user })} className="px-3 py-1.5 rounded-lg bg-orange-500/20 text-orange-400 text-xs font-bold hover:bg-orange-500/30 transition-colors border border-orange-500/20 inline-flex items-center gap-1">
                        <FiUserPlus /> Assign Clan
                      </button>
                    </td>
                  </tr>
                ))}
                {unassignedQuery.data?.length === 0 && (
                  <tr><td colSpan="5" className="p-8 text-center text-tertiary text-sm">No unassigned recruits found.</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </BaseCard>
      </div>

      {/* Assign Modal */}
      <AnimatePresence>
        {assignModal.open && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className="w-full max-w-md">
              <BaseCard className="p-6 space-y-6">
                <div className="flex justify-between items-center">
                  <h3 className="text-lg font-black text-primary">Assign Recruit</h3>
                  <button onClick={() => setAssignModal({ open: false, user: null })} className="text-tertiary hover:text-primary"><FiX size={20} /></button>
                </div>

                <div>
                  <p className="text-sm text-secondary mb-4">Assigning <strong className="text-white">{assignModal.user.username}</strong> to a clan. This will notify the member and the Clan Chief via email.</p>
                  <label className="field-label">Select Clan</label>
                  <select className="field-select w-full" value={selectedClanForAssign} onChange={(e) => setSelectedClanForAssign(e.target.value)}>
                    <option value="">-- Choose a Clan --</option>
                    {clansQuery.data?.map(c => (
                      <option key={c._id} value={c._id}>{c.name} ({c.memberCount} members) - Chief: {c.chief?.username || 'None'}</option>
                    ))}
                  </select>
                </div>

                <div className="flex gap-3 justify-end">
                  <button onClick={() => setAssignModal({ open: false, user: null })} className="px-4 py-2 rounded-xl font-bold text-sm bg-white/5 text-secondary hover:bg-white/10 hover:text-white transition-colors">Cancel</button>
                  <button onClick={handleAssign} disabled={assignMutation.isLoading || !selectedClanForAssign} className="btn-primary px-6 py-2 text-sm">
                    {assignMutation.isLoading ? 'Assigning...' : 'Confirm Assignment'}
                  </button>
                </div>
              </BaseCard>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

      {/* Create Clan Modal */}
      <AnimatePresence>
        {createModal.open && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className="w-full max-w-md">
              <BaseCard className="p-6 space-y-4">
                <div className="flex justify-between items-center mb-2">
                  <h3 className="text-lg font-black text-primary flex items-center gap-2"><FiShield className="text-accent"/> Create New Clan</h3>
                  <button onClick={() => setCreateModal({ ...createModal, open: false })} className="text-tertiary hover:text-primary"><FiX size={20} /></button>
                </div>

                <div className="space-y-3">
                  <div>
                     <label className="field-label">Clan Name</label>
                     <input className="field-input w-full" placeholder="e.g. Cyber Ninjas" value={createModal.name} onChange={e => setCreateModal(m => ({...m, name: e.target.value}))} />
                  </div>
                  <div>
                     <label className="field-label">Clan Tag (Unique)</label>
                     <input className="field-input w-full uppercase font-mono" placeholder="e.g. CYBER" maxLength={5} value={createModal.tag} onChange={e => setCreateModal(m => ({...m, tag: e.target.value.toUpperCase()}))} />
                  </div>
                  <div>
                     <label className="field-label">Description</label>
                     <textarea className="field-input w-full min-h-[80px]" placeholder="Brief lore or description..." value={createModal.description} onChange={e => setCreateModal(m => ({...m, description: e.target.value}))} />
                  </div>
                </div>

                <div className="flex gap-3 justify-end pt-4">
                  <button onClick={() => setCreateModal({ ...createModal, open: false })} className="px-4 py-2 rounded-xl font-bold text-sm bg-white/5 text-secondary hover:bg-white/10 hover:text-white transition-colors">Cancel</button>
                  <button 
                    onClick={() => createMutation.mutate({ name: createModal.name, tag: createModal.tag, description: createModal.description })} 
                    disabled={createMutation.isLoading || !createModal.name || !createModal.tag} 
                    className="btn-primary px-6 py-2 text-sm"
                  >
                    {createMutation.isLoading ? 'Creating...' : 'Create Clan'}
                  </button>
                </div>
              </BaseCard>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

    </div>
  );
};

