import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { motion } from 'framer-motion';
import { FiSearch, FiFilter, FiAward, FiStar, FiUserCheck, FiUserX, FiAlertCircle, FiUsers, FiMoreVertical, FiEdit2, FiTrash2, FiShield } from 'react-icons/fi';
import BaseCard from '../../components/BaseCard';
import MemberHoverCard from '../../components/MemberHoverCard';
import { api } from '../../lib/api';
import toast from 'react-hot-toast';

import { USE_MOCK, mockLeaderboardMembers } from '../../lib/mockData';

const MembersTab = () => {
  const queryClient = useQueryClient();
  const [search, setSearch] = useState('');
  const [levelFilter, setLevelFilter] = useState('');
  const [clanFilter, setClanFilter] = useState('');
  const [menuOpen, setMenuOpen] = useState(null);

  const usersQuery = useQuery({
    queryKey: ['admin-all-users'],
    queryFn: async () => {
      try {
        if (USE_MOCK) return mockLeaderboardMembers;
        const res = await api.get('/api/users');
        return res.data.data || [];
      } catch (err) {
        console.warn("Failed to fetch users, using mock data.", err);
        return mockLeaderboardMembers;
      }
    }
  });

  const clansQuery = useQuery({
    queryKey: ['admin-clans-list'],
    queryFn: async () => {
      const res = await api.get('/api/clans');
      return res.data.data || [];
    }
  });

  const updateRoleMutation = useMutation({
    mutationFn: async ({ userId, role }) => {
      return api.put(`/api/users/${userId}/role`, { role });
    },
    onSuccess: () => {
      toast.success("Role updated successfully");
      queryClient.invalidateQueries(['admin-all-users']);
      setMenuOpen(null);
    },
    onError: () => {
      toast.error("Failed to update role");
    }
  });

  const banUserMutation = useMutation({
    mutationFn: async (userId) => {
      return api.put(`/api/users/${userId}/ban`);
    },
    onSuccess: () => {
      toast.success("User banned");
      queryClient.invalidateQueries(['admin-all-users']);
      setMenuOpen(null);
    },
    onError: () => {
      toast.error("Failed to ban user");
    }
  });

  // Filter users
  const filteredUsers = (usersQuery.data || []).filter(u => {
    const s = search.toLowerCase();
    const matchSearch = u.username.toLowerCase().includes(s) || (u.regNo && u.regNo.toLowerCase().includes(s));
    const matchLevel = levelFilter ? u.codingLevel === levelFilter : true;
    const matchClan = clanFilter ? u.clan?._id === clanFilter || u.clan === clanFilter : true;
    return matchSearch && matchLevel && matchClan && u.role !== 'admin'; // hide admins maybe? Or keep them
  });

  const getStatusDot = (status) => {
    switch(status) {
      case 'Active': return <div className="w-2 h-2 rounded-full bg-green-500 shadow-[0_0_8px_#22c55e]" />;
      case 'Warned': return <div className="w-2 h-2 rounded-full bg-red-500 shadow-[0_0_8px_#ef4444]" />;
      default: return <div className="w-2 h-2 rounded-full bg-gray-500" />;
    }
  };

  const getLevelColor = (level) => {
    switch(level) {
      case 'Beginner': return 'bg-white/5 border-white/10 text-secondary';
      case 'Intermediate': return 'bg-yellow-500/10 border-yellow-500/20 text-yellow-400';
      case 'Advanced': return 'bg-red-500/10 border-red-500/20 text-red-400';
      default: return 'bg-white/5 border-white/10 text-secondary';
    }
  };

  return (
    <div className="space-y-6">
      {/* Header & Filters */}
      <div className="flex flex-col lg:flex-row justify-between gap-4">
        <h2 className="text-section-title font-bold flex items-center gap-2"><FiUsers className="text-green-400" /> Member Directory</h2>

        <div className="flex flex-wrap gap-3">
          <div className="relative">
            <FiSearch className="absolute left-3 top-1/2 -translate-y-1/2 text-tertiary" />
            <input className="field-input pl-9 w-full md:w-64" placeholder="Search name or Reg No..." value={search} onChange={e => setSearch(e.target.value)} />
          </div>

          <div className="relative">
            <FiFilter className="absolute left-3 top-1/2 -translate-y-1/2 text-tertiary" />
            <select className="field-select pl-9 appearance-none" value={levelFilter} onChange={e => setLevelFilter(e.target.value)}>
              <option value="">All Levels</option>
              <option value="Beginner">Beginner</option>
              <option value="Intermediate">Intermediate</option>
              <option value="Advanced">Advanced</option>
            </select>
          </div>

          <div className="relative">
            <FiFilter className="absolute left-3 top-1/2 -translate-y-1/2 text-tertiary" />
            <select className="field-select pl-9 appearance-none" value={clanFilter} onChange={e => setClanFilter(e.target.value)}>
              <option value="">All Clans</option>
              {clansQuery.data?.map(c => <option key={c._id} value={c._id}>{c.name}</option>)}
            </select>
          </div>
        </div>
      </div>

      <BaseCard className="p-0 overflow-hidden">
        <div className="overflow-x-auto min-h-[400px]">
          <table className="w-full text-left border-collapse relative">
            <thead>
              <tr className="bg-white/[0.02] border-b border-white/[0.05] text-xs uppercase tracking-widest text-tertiary font-bold">
                <th className="p-4 pl-6">Member</th>
                <th className="p-4">Reg No</th>
                <th className="p-4">Clan</th>
                <th className="p-4">Level</th>
                <th className="p-4 text-center">Stats</th>
                <th className="p-4 text-center">Status</th>
                <th className="p-4 text-right pr-6">Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredUsers.map((user, i) => (
                <motion.tr key={user._id} initial={{ opacity: 0, y: 5 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.02 }} className="border-b border-white/[0.02] hover:bg-white/[0.01] transition-colors group">
                  <td className="p-4 pl-6 font-bold text-sm text-primary">
                    <MemberHoverCard userId={user._id} username={user.username}>
                      <div className="flex items-center gap-3 cursor-pointer">
                        <div className="w-8 h-8 rounded-full bg-accent/20 text-accent flex items-center justify-center font-black transition-colors">
                          {user.username[0].toUpperCase()}
                        </div>
                        <span className="transition-colors">{user.username}</span>
                      </div>
                    </MemberHoverCard>
                  </td>
                  <td className="p-4 text-sm text-secondary font-mono">{user.regNo || '---'}</td>
                  <td className="p-4 text-sm">
                    {user.clan ? (
                      <span className="text-secondary">{clansQuery.data?.find(c => c._id === user.clan || c._id === user.clan?._id)?.name || 'Unknown'}</span>
                    ) : (
                      <span className="text-tertiary italic">Unassigned</span>
                    )}
                  </td>
                  <td className="p-4">
                    <span className={`px-2 py-1 rounded text-[10px] font-bold border uppercase tracking-widest ${getLevelColor(user.codingLevel)}`}>
                      {user.codingLevel}
                    </span>
                  </td>
                  <td className="p-4 text-center">
                    <div className="flex justify-center gap-3 text-xs font-mono">
                      <span className="text-accent flex items-center gap-1" title="Points"><FiStar /> {user.points || 0}</span>
                      <span className="text-orange-400 flex items-center gap-1" title="Streak">🔥 {user.streak || 0}</span>
                    </div>
                  </td>
                  <td className="p-4 text-center">
                    <div className="flex justify-center" title={user.status || 'Active'}>
                      {getStatusDot(user.status || 'Active')}
                    </div>
                  </td>
                  <td className="p-4 text-right pr-6 relative">
                    <button 
                      onClick={() => setMenuOpen(menuOpen === user._id ? null : user._id)}
                      className="p-2 hover:bg-white/10 rounded-lg transition-colors opacity-0 group-hover:opacity-100 focus:opacity-100 text-tertiary"
                    >
                      <FiMoreVertical />
                    </button>
                    {menuOpen === user._id && (
                       <div className="absolute right-10 top-4 w-48 bg-[#121218] border border-white/10 rounded-xl shadow-2xl overflow-hidden z-50">
                         <div className="p-1">
                            <button 
                              onClick={() => updateRoleMutation.mutate({ userId: user._id, role: 'clan-chief' })}
                              className="w-full text-left px-3 py-2 text-sm text-secondary hover:text-white hover:bg-white/5 rounded flex items-center gap-2"
                            >
                              <FiShield className="text-blue-400" /> Make Clan Chief
                            </button>
                            <button 
                              onClick={() => updateRoleMutation.mutate({ userId: user._id, role: 'member' })}
                              className="w-full text-left px-3 py-2 text-sm text-secondary hover:text-white hover:bg-white/5 rounded flex items-center gap-2"
                            >
                              <FiUserCheck className="text-green-400" /> Make Member
                            </button>
                            <div className="h-px bg-white/10 my-1 mx-2" />
                            <button 
                              onClick={() => {
                                if(window.confirm(`Ban user ${user.username}?`)) {
                                  banUserMutation.mutate(user._id);
                                }
                              }}
                              className="w-full text-left px-3 py-2 text-sm text-red-400 hover:text-red-300 hover:bg-red-500/10 rounded flex items-center gap-2"
                            >
                              <FiUserX /> Ban User
                            </button>
                         </div>
                       </div>
                    )}
                  </td>
                </motion.tr>
              ))}
              {filteredUsers.length === 0 && (
                <tr><td colSpan="7" className="p-10 text-center text-tertiary">No members found matching the criteria.</td></tr>
              )}
            </tbody>
          </table>
        </div>
        <div className="p-3 border-t border-white/[0.05] bg-white/[0.01] text-xs text-tertiary flex justify-between items-center px-6">
          <span>Showing {filteredUsers.length} members</span>
        </div>
      </BaseCard>

      {menuOpen && (
        <div className="fixed inset-0 z-40" onClick={() => setMenuOpen(null)} />
      )}
    </div>
  );
};

export default MembersTab;

import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import toast from 'react-hot-toast';
import { motion, AnimatePresence } from 'framer-motion';
import { FiPlus, FiTrash2, FiBell, FiX, FiCheck, FiInfo, FiAlertTriangle, FiStar } from 'react-icons/fi';
import BaseCard from '../../components/BaseCard';
import { api } from '../../lib/api';

const NoticeBoardTab = () => {
  const queryClient = useQueryClient();
  const [createModal, setCreateModal] = useState(false);
  const [form, setForm] = useState({ content: '', priority: 'General', isPinned: false });

  const noticesQuery = useQuery({
    queryKey: ['admin-notices'],
    queryFn: async () => {
      const res = await api.get('/api/notices/history');
      return res.data.data || [];
    }
  });

  const createMutation = useMutation({
    mutationFn: async (data) => {
      const res = await api.post('/api/notices', data);
      return res.data;
    },
    onSuccess: () => {
      toast.success('Notice published globally!');
      queryClient.invalidateQueries(['admin-notices']);
      setCreateModal(false);
      setForm({ content: '', priority: 'General', isPinned: false });
    },
    onError: (err) => {
      toast.error(err.response?.data?.message || 'Failed to publish notice');
    }
  });

  const deleteMutation = useMutation({
    mutationFn: async (id) => {
      const res = await api.delete(`/api/notices/${id}`);
      return res.data;
    },
    onSuccess: () => {
      toast.success('Notice removed');
      queryClient.invalidateQueries(['admin-notices']);
    }
  });

  const handleCreate = (e) => {
    e.preventDefault();
    createMutation.mutate(form);
  };

  const getPriorityColors = (priority) => {
    switch(priority) {
      case 'Urgent': return 'border-red-500/50 bg-red-500/10 text-red-400';
      case 'Info': return 'border-blue-500/50 bg-blue-500/10 text-blue-400';
      default: return 'border-purple-500/50 bg-purple-500/10 text-purple-400';
    }
  };

  const getPriorityIcon = (priority) => {
    switch(priority) {
      case 'Urgent': return <FiAlertTriangle />;
      case 'Info': return <FiInfo />;
      default: return <FiBell />;
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-section-title font-bold flex items-center gap-2"><FiBell className="text-yellow-400" /> Global Notice Board</h2>
        <button onClick={() => setCreateModal(true)} className="btn-primary py-2 px-4 text-sm flex items-center gap-2 shadow-[0_0_15px_rgba(234,179,8,0.3)] !bg-yellow-500 hover:!bg-yellow-600 !text-black">
          <FiPlus /> New Broadcast
        </button>
      </div>

      <div className="space-y-4">
        {noticesQuery.data?.map((notice, i) => (
          <motion.div key={notice._id} initial={{ opacity: 0, x: -10 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: i * 0.1 }}>
            <BaseCard className={`p-5 flex flex-col gap-3 relative overflow-hidden border-l-4 ${getPriorityColors(notice.priority).split(' ')[0]}`}>
              {notice.isPinned && (
                <div className="absolute top-0 right-0 bg-yellow-500 text-black text-[10px] font-black uppercase px-3 py-1 rounded-bl-xl shadow flex items-center gap-1">
                  <FiStar size={10} /> Pinned
                </div>
              )}
              <div className="flex justify-between items-start pr-16">
                <div className={`flex items-center gap-2 text-xs font-black uppercase tracking-widest px-2 py-1 rounded ${getPriorityColors(notice.priority)}`}>
                  {getPriorityIcon(notice.priority)} {notice.priority}
                </div>
                <button onClick={() => { if(window.confirm('Delete this notice?')) deleteMutation.mutate(notice._id); }} className="text-red-400 hover:text-red-300 p-1 bg-red-500/10 rounded-lg">
                  <FiTrash2 size={16} />
                </button>
              </div>
              <p className="text-primary leading-relaxed text-sm">{notice.content}</p>
              <div className="text-[10px] text-tertiary flex items-center gap-2 font-mono">
                <span>By {notice.createdBy?.username || 'Admin'}</span> • <span>{new Date(notice.createdAt).toLocaleString()}</span>
              </div>
            </BaseCard>
          </motion.div>
        ))}
        {noticesQuery.data?.length === 0 && (
          <div className="text-center py-10 text-tertiary">No notices broadcasted yet.</div>
        )}
      </div>

      <AnimatePresence>
        {createModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className="w-full max-w-lg">
              <BaseCard className="p-6 space-y-6 border border-yellow-500/30">
                <div className="flex justify-between items-center">
                  <h3 className="text-lg font-black text-primary">New Broadcast</h3>
                  <button onClick={() => setCreateModal(false)} className="text-tertiary hover:text-primary"><FiX size={20} /></button>
                </div>

                <form onSubmit={handleCreate} className="space-y-4">
                  <div>
                    <label className="field-label">Priority Level</label>
                    <div className="grid grid-cols-3 gap-2 mt-1">
                      {['General', 'Info', 'Urgent'].map(p => (
                        <button type="button" key={p} onClick={() => setForm({...form, priority: p})} 
                          className={`py-2 px-3 rounded-xl border text-xs font-bold transition-all flex items-center justify-center gap-2
                          ${form.priority === p ? getPriorityColors(p) + ' scale-105' : 'border-white/10 bg-white/5 text-secondary hover:bg-white/10'}`}>
                          {getPriorityIcon(p)} {p}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div>
                    <label className="field-label">Message Content</label>
                    <textarea required rows="4" className="field-textarea text-sm" placeholder="Enter the announcement..." value={form.content} onChange={e => setForm({...form, content: e.target.value})} />
                  </div>

                  <div className="flex items-center gap-3">
                    <button type="button" onClick={() => setForm({...form, isPinned: !form.isPinned})} className={`w-10 h-6 rounded-full p-1 transition-colors ${form.isPinned ? 'bg-yellow-500' : 'bg-white/10'}`}>
                      <motion.div className="w-4 h-4 bg-white rounded-full shadow" animate={{ x: form.isPinned ? 16 : 0 }} />
                    </button>
                    <span className="text-sm font-bold text-secondary flex items-center gap-1"><FiStar className="text-yellow-500"/> Pin to top</span>
                  </div>

                  <div className="flex gap-3 justify-end pt-4">
                    <button type="button" onClick={() => setCreateModal(false)} className="px-4 py-2 rounded-xl font-bold text-sm bg-white/5 text-secondary hover:bg-white/10 transition-colors">Cancel</button>
                    <button type="submit" disabled={createMutation.isLoading} className="btn-primary px-6 py-2 text-sm !bg-yellow-500 hover:!bg-yellow-600 !text-black shadow-[0_0_15px_rgba(234,179,8,0.3)]">
                      {createMutation.isLoading ? 'Broadcasting...' : 'Broadcast & Notify'}
                    </button>
                  </div>
                </form>
              </BaseCard>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default NoticeBoardTab;

import React, { useState, useRef } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import toast from 'react-hot-toast';
import { motion, AnimatePresence } from 'framer-motion';
import { FiPlus, FiTrash2, FiClock, FiTarget, FiZap, FiEdit3, FiCalendar, FiUploadCloud, FiX } from 'react-icons/fi';
import BaseCard from '../../components/BaseCard';
import { api } from '../../lib/api';

const initialQuestionState = {
  title: '',
  difficulty: 'Easy',
  points: 100,
  category: '',
  description: '',
  hints: ['']
};

const QuestionSetsTab = () => {
  const queryClient = useQueryClient();
  const [view, setView] = useState('list'); // 'list', 'history', 'create'
  const [importModalOpen, setImportModalOpen] = useState(false);
  const fileInputRef = useRef(null);

  const setsQuery = useQuery({
    queryKey: ['admin-question-sets'],
    queryFn: async () => {
      try {
        const res = await api.get('/api/sets');
        return res.data.data || [];
      } catch (err) {
        return [];
      }
    }
  });

  const [form, setForm] = useState({
    title: '',
    weekNumber: 1,
    deadline: '',
    targetLevel: 'Both',
    questions: [{ ...initialQuestionState }]
  });

  const createSetMutation = useMutation({
    mutationFn: async (data) => {
      const res = await api.post('/api/sets', data);
      return res.data;
    },
    onSuccess: () => {
      toast.success('Question Set published! Emails sent to members.');
      queryClient.invalidateQueries(['admin-question-sets']);
      setView('list');
      setForm({
        title: '', weekNumber: 1, deadline: '', targetLevel: 'Both', questions: [{ ...initialQuestionState }]
      });
    },
    onError: (err) => {
      toast.error(err.response?.data?.message || 'Failed to publish set');
    }
  });

  const importMutation = useMutation({
    mutationFn: async (file) => {
      const formData = new FormData();
      formData.append('file', file);
      const res = await api.post('/api/challenges/import', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      return res.data;
    },
    onSuccess: (data) => {
      toast.success(data.message || 'Challenges imported successfully!');
      queryClient.invalidateQueries(['admin-question-sets']);
      setImportModalOpen(false);
    },
    onError: (err) => {
      toast.error(err.response?.data?.message || 'Failed to import challenges');
    }
  });

  const handleFileChange = (e) => {
    const file = e.target.files?.[0];
    if (file) {
      importMutation.mutate(file);
    }
  };

  const handleAddQuestion = () => {
    if (form.questions.length >= 5) {
      toast.error('Maximum 5 questions per set allowed.');
      return;
    }
    setForm(prev => ({ ...prev, questions: [...prev.questions, { ...initialQuestionState }] }));
  };

  const handleRemoveQuestion = (index) => {
    if (form.questions.length === 1) return;
    setForm(prev => ({ ...prev, questions: prev.questions.filter((_, i) => i !== index) }));
  };

  const updateQuestion = (index, field, value) => {
    const newQs = [...form.questions];
    newQs[index][field] = value;
    setForm({ ...form, questions: newQs });
  };

  const updateHint = (qIndex, hIndex, value) => {
    const newQs = [...form.questions];
    newQs[qIndex].hints[hIndex] = value;
    setForm({ ...form, questions: newQs });
  };

  const handlePublish = (e) => {
    e.preventDefault();
    createSetMutation.mutate(form);
  };

  return (
    <div className="space-y-6">
      {/* Navigation */}
      <div className="flex gap-2">
        <button onClick={() => setView('list')} className={`px-4 py-2 rounded-xl text-sm font-bold transition-colors ${view === 'list' ? 'bg-accent text-white' : 'bg-white/5 text-secondary hover:text-primary'}`}>Active Sets</button>
        <button onClick={() => setView('history')} className={`px-4 py-2 rounded-xl text-sm font-bold transition-colors ${view === 'history' ? 'bg-accent text-white' : 'bg-white/5 text-secondary hover:text-primary'}`}>History</button>
        <div className="ml-auto flex items-center gap-3">
          <button onClick={() => setImportModalOpen(true)} className="px-4 py-2 rounded-xl text-sm font-bold transition-colors bg-purple-500/20 text-purple-400 hover:bg-purple-500/30 flex items-center gap-2">
            <FiUploadCloud /> Import
          </button>
          <button onClick={() => setView('create')} className={`px-4 py-2 rounded-xl text-sm font-bold transition-colors flex items-center gap-2 ${view === 'create' ? 'bg-green-500 text-white' : 'bg-green-500/20 text-green-400 hover:bg-green-500/30'}`}>
            <FiPlus /> Create New Set
          </button>
        </div>
      </div>

      {view === 'create' && (
        <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="max-w-4xl mx-auto space-y-6">
          <form onSubmit={handlePublish} className="space-y-6">
            <BaseCard className="p-6 space-y-4 border-l-4 border-l-accent">
              <h2 className="text-xl font-black text-primary">Set Details</h2>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="field-label">Set Title</label>
                  <input required className="field-input" placeholder="e.g. Dynamic Programming Basics" value={form.title} onChange={e => setForm({...form, title: e.target.value})} />
                </div>
                <div>
                  <label className="field-label">Target Level</label>
                  <div className="flex bg-white/5 p-1 rounded-xl">
                    {['Beginner', 'Intermediate', 'Both'].map(lvl => (
                      <button type="button" key={lvl} onClick={() => setForm({...form, targetLevel: lvl})} className={`flex-1 py-1.5 text-xs font-bold rounded-lg transition-colors ${form.targetLevel === lvl ? 'bg-white/10 text-primary shadow' : 'text-tertiary hover:text-secondary'}`}>{lvl}</button>
                    ))}
                  </div>
                </div>
                <div>
                  <label className="field-label">Week Number</label>
                  <div className="relative">
                    <FiCalendar className="absolute left-3 top-1/2 -translate-y-1/2 text-tertiary" />
                    <input required type="number" min="1" className="field-input pl-9" value={form.weekNumber} onChange={e => setForm({...form, weekNumber: Number(e.target.value)})} />
                  </div>
                </div>
                <div>
                  <label className="field-label">Deadline</label>
                  <input required type="date" className="field-input" value={form.deadline} onChange={e => setForm({...form, deadline: e.target.value})} />
                </div>
              </div>
            </BaseCard>

            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <h2 className="text-lg font-black text-primary">Questions ({form.questions.length}/5)</h2>
                {form.questions.length < 5 && (
                  <button type="button" onClick={handleAddQuestion} className="text-xs font-bold text-accent bg-accent/10 px-3 py-1.5 rounded-lg hover:bg-accent/20 transition-colors flex items-center gap-1">
                    <FiPlus /> Add Question
                  </button>
                )}
              </div>

              <AnimatePresence>
                {form.questions.map((q, i) => (
                  <motion.div key={i} initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} exit={{ opacity: 0, height: 0 }}>
                    <BaseCard className="p-5 space-y-4 relative overflow-hidden group">
                      <div className="absolute top-0 left-0 w-1 h-full bg-blue-500/50" />
                      <div className="flex justify-between items-start">
                        <h3 className="font-bold text-primary flex items-center gap-2">
                          <span className="w-6 h-6 rounded bg-white/10 flex items-center justify-center text-xs text-secondary">{i+1}</span>
                          Question Config
                        </h3>
                        {form.questions.length > 1 && (
                          <button type="button" onClick={() => handleRemoveQuestion(i)} className="text-red-400 hover:text-red-300 p-1">
                            <FiTrash2 size={16} />
                          </button>
                        )}
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                        <div className="md:col-span-2">
                          <label className="field-label text-[10px]">Title</label>
                          <input required className="field-input text-sm" value={q.title} onChange={e => updateQuestion(i, 'title', e.target.value)} />
                        </div>
                        <div>
                          <label className="field-label text-[10px]">Difficulty</label>
                          <select className="field-select text-sm" value={q.difficulty} onChange={e => updateQuestion(i, 'difficulty', e.target.value)}>
                            <option>Easy</option><option>Medium</option><option>Hard</option>
                          </select>
                        </div>
                        <div>
                          <label className="field-label text-[10px]">Points</label>
                          <input required type="number" className="field-input text-sm" value={q.points} onChange={e => updateQuestion(i, 'points', Number(e.target.value))} />
                        </div>
                        <div>
                          <label className="field-label text-[10px]">Tags/Category</label>
                          <input className="field-input text-sm" placeholder="e.g. Arrays, Sorting" value={q.category} onChange={e => updateQuestion(i, 'category', e.target.value)} />
                        </div>
                        <div className="md:col-span-3">
                          <label className="field-label text-[10px]">Problem Description</label>
                          <textarea required rows="3" className="field-textarea text-sm" value={q.description} onChange={e => updateQuestion(i, 'description', e.target.value)} />
                        </div>
                        <div className="md:col-span-3">
                          <label className="field-label text-[10px]">Hints (optional)</label>
                          {q.hints.map((hint, hi) => (
                            <input key={hi} className="field-input text-sm mb-2" placeholder="Hint..." value={hint} onChange={e => updateHint(i, hi, e.target.value)} />
                          ))}
                        </div>
                      </div>
                    </BaseCard>
                  </motion.div>
                ))}
              </AnimatePresence>
            </div>

            <div className="flex justify-end">
              <button type="submit" disabled={createSetMutation.isLoading} className="btn-primary w-full md:w-auto px-8 py-3 text-sm font-bold shadow-[0_0_20px_rgba(168,85,247,0.4)]">
                {createSetMutation.isLoading ? 'Publishing...' : 'Publish Question Set & Notify'}
              </button>
            </div>
          </form>
        </motion.div>
      )}

      {(view === 'list' || view === 'history') && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {setsQuery.data?.map((set, i) => {
            const isHistory = new Date(set.deadline) < new Date();
            if (view === 'list' && isHistory) return null;
            if (view === 'history' && !isHistory) return null;

            return (
              <motion.div key={set._id} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.05 }}>
                <BaseCard className="p-5 flex flex-col gap-4">
                  <div className="flex justify-between items-start">
                    <div>
                      <h3 className="font-bold text-lg text-primary">{set.title}</h3>
                      <p className="text-xs text-secondary font-mono flex items-center gap-2 mt-1">
                        <FiTarget className="text-accent"/> Target: {set.targetLevel} 
                        <span className="text-white/20">|</span> 
                        <FiClock className="text-orange-400"/> Due: {new Date(set.deadline).toLocaleDateString()}
                      </p>
                    </div>
                    <span className="bg-white/5 border border-white/10 px-3 py-1 rounded-lg text-xs font-black uppercase tracking-widest">
                      Week {set.weekNumber}
                    </span>
                  </div>
                  <div className="h-px bg-white/5" />
                  <div className="space-y-2">
                    {set.questions.map((q, qi) => {
                      const diffColor = q.difficulty === 'Easy' ? 'text-green-400' : q.difficulty === 'Medium' ? 'text-yellow-400' : 'text-red-400';
                      return (
                        <div key={qi} className="flex justify-between items-center text-sm p-2 rounded-lg bg-white/[0.02] hover:bg-white/[0.04] transition-colors border border-transparent hover:border-white/5">
                          <span className="text-secondary truncate pr-2 max-w-[60%] font-medium">{q.title}</span>
                          <div className="flex gap-3 text-xs font-bold">
                            <span className={diffColor}>{q.difficulty}</span>
                            <span className="text-accent flex items-center gap-1"><FiZap size={10}/> {q.points} XP</span>
                          </div>
                        </div>
                      )
                    })}
                  </div>
                </BaseCard>
              </motion.div>
            )
          })}
        </div>
      )}

      {/* Import Modal */}
      <AnimatePresence>
        {importModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className="w-full max-w-md">
              <BaseCard className="p-6 space-y-4">
                <div className="flex justify-between items-center mb-2">
                  <h3 className="text-lg font-black text-primary flex items-center gap-2"><FiUploadCloud className="text-purple-400"/> Import Questions</h3>
                  <button onClick={() => setImportModalOpen(false)} className="text-tertiary hover:text-primary"><FiX size={20} /></button>
                </div>

                <p className="text-sm text-secondary">Upload a <strong>.json</strong>, <strong>.csv</strong>, or <strong>.docx</strong> file to bulk import challenges into the database.</p>

                <div 
                  className="border-2 border-dashed border-white/10 rounded-xl p-8 flex flex-col items-center justify-center cursor-pointer hover:border-purple-400/50 hover:bg-purple-400/5 transition-all text-center"
                  onClick={() => fileInputRef.current?.click()}
                >
                  <FiUploadCloud className="text-4xl text-tertiary mb-3" />
                  <p className="font-bold text-primary mb-1">Click or drag file to upload</p>
                  <p className="text-xs text-tertiary">Supported: JSON, CSV, DOCX</p>
                  <input 
                    type="file" 
                    ref={fileInputRef} 
                    className="hidden" 
                    accept=".json,.csv,.docx" 
                    onChange={handleFileChange} 
                  />
                </div>

                {importMutation.isLoading && (
                  <div className="text-center text-sm text-purple-400 animate-pulse font-bold">
                    Importing... Please wait...
                  </div>
                )}
              </BaseCard>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default QuestionSetsTab;

import React, { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import toast from 'react-hot-toast';
import { motion, AnimatePresence } from 'framer-motion';
import { FiPlus, FiTrash2, FiFolder, FiFileText, FiLink, FiDownload, FiX, FiUploadCloud } from 'react-icons/fi';
import BaseCard from '../../components/BaseCard';
import { api } from '../../lib/api';

const TOPICS = ['Arrays', 'Linked Lists', 'DP', 'Graphs', 'Trees', 'Stacks & Queues', 'Strings', 'Sorting'];

const ResourcesTab = () => {
  const queryClient = useQueryClient();
  const [activeFolder, setActiveFolder] = useState('Arrays');
  const [uploadModal, setUploadModal] = useState(false);
  const [form, setForm] = useState({ title: '', folder: 'Arrays', type: 'PDF', url: '', sizeBytes: 0 });
  const [dragActive, setDragActive] = useState(false);
  const [fileName, setFileName] = useState('');

  const resourcesQuery = useQuery({
    queryKey: ['admin-resources', activeFolder],
    queryFn: async () => {
      const res = await api.get(`/api/resources?folder=${encodeURIComponent(activeFolder)}`);
      return res.data.data || [];
    }
  });

  const uploadMutation = useMutation({
    mutationFn: async (data) => {
      const res = await api.post('/api/resources', data);
      return res.data;
    },
    onSuccess: () => {
      toast.success('Resource added!');
      queryClient.invalidateQueries(['admin-resources']);
      setUploadModal(false);
      setForm({ title: '', folder: activeFolder, type: 'PDF', url: '', sizeBytes: 0 });
      setFileName('');
    },
    onError: (err) => {
      toast.error(err.response?.data?.message || 'Failed to upload');
    }
  });

  const deleteMutation = useMutation({
    mutationFn: async (id) => {
      const res = await api.delete(`/api/resources/${id}`);
      return res.data;
    },
    onSuccess: () => {
      toast.success('Resource deleted');
      queryClient.invalidateQueries(['admin-resources']);
    }
  });

  const handleDrag = (e) => {
    e.preventDefault(); e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') setDragActive(true);
    else if (e.type === 'dragleave') setDragActive(false);
  };

  const handleDrop = (e) => {
    e.preventDefault(); e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      handleFile(e.dataTransfer.files[0]);
    }
  };

  const handleFile = (file) => {
    if (file.size > 20 * 1024 * 1024) {
      toast.error('File exceeds 20MB limit');
      return;
    }
    setFileName(file.name);
    if (!form.title) setForm(p => ({ ...p, title: file.name.replace('.pdf', '') }));
    setForm(p => ({ ...p, type: 'PDF', sizeBytes: file.size, url: URL.createObjectURL(file) })); // Mock URL
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (form.type === 'PDF' && !form.url) {
      toast.error('Please upload a PDF file'); return;
    }
    uploadMutation.mutate(form);
  };

  const formatSize = (bytes) => {
    if (!bytes) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
  };

  return (
    <div className="flex flex-col md:flex-row gap-6">
      {/* Folders Sidebar */}
      <div className="w-full md:w-64 space-y-4">
        <h2 className="text-section-title font-bold flex items-center gap-2"><FiFolder className="text-blue-400" /> Library</h2>
        <BaseCard className="p-2 space-y-1">
          {TOPICS.map(topic => (
            <button
              key={topic}
              onClick={() => setActiveFolder(topic)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-bold transition-all
                ${activeFolder === topic ? 'bg-blue-500/20 text-blue-400 border border-blue-500/30' : 'text-secondary hover:bg-white/5 hover:text-primary border border-transparent'}`}
            >
              <FiFolder className={activeFolder === topic ? 'fill-blue-500/20' : ''} />
              {topic}
            </button>
          ))}
        </BaseCard>
      </div>

      {/* Main Content */}
      <div className="flex-1 space-y-4">
        <div className="flex justify-between items-center">
          <div>
            <h2 className="text-xl font-black text-primary">{activeFolder}</h2>
            <p className="text-sm text-secondary">Manage study materials and resources.</p>
          </div>
          <button onClick={() => { setForm(p => ({ ...p, folder: activeFolder })); setUploadModal(true); }} className="btn-primary py-2 px-4 text-sm flex items-center gap-2 !bg-blue-500 hover:!bg-blue-600 shadow-[0_0_15px_rgba(59,130,246,0.3)]">
            <FiPlus /> Add Resource
          </button>
        </div>

        <div className="grid grid-cols-1 xl:grid-cols-2 gap-4">
          {resourcesQuery.data?.map((res, i) => (
            <motion.div key={res._id} initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: i * 0.05 }}>
              <BaseCard className="p-4 flex items-center gap-4 group">
                <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${res.type === 'PDF' ? 'bg-red-500/10 text-red-400' : 'bg-blue-500/10 text-blue-400'}`}>
                  {res.type === 'PDF' ? <FiFileText size={24} /> : <FiLink size={24} />}
                </div>
                <div className="flex-1 min-w-0">
                  <h3 className="font-bold text-primary truncate group-hover:text-blue-400 transition-colors">{res.title}</h3>
                  <div className="flex gap-3 text-[10px] font-mono text-tertiary mt-1">
                    <span className="uppercase font-bold">{res.type}</span>
                    {res.sizeBytes > 0 && <span>{formatSize(res.sizeBytes)}</span>}
                    <span>Added {new Date(res.createdAt).toLocaleDateString()}</span>
                  </div>
                </div>
                <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <a href={res.url} target="_blank" rel="noopener noreferrer" className="p-2 rounded-lg bg-white/5 text-secondary hover:bg-white/10 hover:text-white transition-colors">
                    {res.type === 'PDF' ? <FiDownload /> : <FiLink />}
                  </a>
                  <button onClick={() => { if(window.confirm('Delete resource?')) deleteMutation.mutate(res._id); }} className="p-2 rounded-lg bg-red-500/10 text-red-400 hover:bg-red-500/20 transition-colors">
                    <FiTrash2 />
                  </button>
                </div>
              </BaseCard>
            </motion.div>
          ))}
          {resourcesQuery.data?.length === 0 && (
            <div className="xl:col-span-2 p-10 text-center border-2 border-dashed border-white/10 rounded-2xl text-tertiary">
              <FiFolder size={48} className="mx-auto mb-4 opacity-20" />
              <p>No resources found in {activeFolder}.</p>
            </div>
          )}
        </div>
      </div>

      <AnimatePresence>
        {uploadModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
            <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className="w-full max-w-md">
              <BaseCard className="p-6 space-y-6 border border-blue-500/30">
                <div className="flex justify-between items-center">
                  <h3 className="text-lg font-black text-primary">Add Resource</h3>
                  <button onClick={() => setUploadModal(false)} className="text-tertiary hover:text-primary"><FiX size={20} /></button>
                </div>

                <div className="flex bg-white/5 p-1 rounded-xl">
                  {['PDF', 'LINK'].map(type => (
                    <button key={type} onClick={() => setForm({ ...form, type, url: '' })} className={`flex-1 py-1.5 text-xs font-bold rounded-lg transition-colors ${form.type === type ? 'bg-blue-500 text-white shadow' : 'text-tertiary hover:text-secondary'}`}>
                      {type}
                    </button>
                  ))}
                </div>

                <form onSubmit={handleSubmit} className="space-y-4">
                  <div>
                    <label className="field-label">Resource Title</label>
                    <input required className="field-input" placeholder="e.g. Graph Algorithms Cheat Sheet" value={form.title} onChange={e => setForm({...form, title: e.target.value})} />
                  </div>

                  <div>
                    <label className="field-label">Folder</label>
                    <select className="field-select" value={form.folder} onChange={e => setForm({...form, folder: e.target.value})}>
                      {TOPICS.map(t => <option key={t} value={t}>{t}</option>)}
                    </select>
                  </div>

                  {form.type === 'LINK' ? (
                    <div>
                      <label className="field-label">External URL</label>
                      <input required type="url" className="field-input" placeholder="https://..." value={form.url} onChange={e => setForm({...form, url: e.target.value})} />
                    </div>
                  ) : (
                    <div>
                      <label className="field-label">Upload PDF</label>
                      <div 
                        onDragEnter={handleDrag} onDragLeave={handleDrag} onDragOver={handleDrag} onDrop={handleDrop}
                        className={`mt-1 border-2 border-dashed rounded-xl p-6 text-center transition-colors cursor-pointer relative overflow-hidden
                          ${dragActive ? 'border-blue-500 bg-blue-500/10' : 'border-white/10 hover:border-blue-500/50 hover:bg-white/5'}`}
                      >
                        <input type="file" accept=".pdf" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" onChange={e => e.target.files[0] && handleFile(e.target.files[0])} />
                        <FiUploadCloud size={32} className={`mx-auto mb-2 ${dragActive ? 'text-blue-400' : 'text-tertiary'}`} />
                        {fileName ? (
                          <p className="text-sm font-bold text-blue-400">{fileName}</p>
                        ) : (
                          <>
                            <p className="text-sm text-secondary font-bold">Drag & drop PDF here</p>
                            <p className="text-xs text-tertiary mt-1">or click to browse (Max 20MB)</p>
                          </>
                        )}
                      </div>
                    </div>
                  )}

                  <div className="flex gap-3 justify-end pt-4">
                    <button type="button" onClick={() => setUploadModal(false)} className="px-4 py-2 rounded-xl font-bold text-sm bg-white/5 text-secondary hover:bg-white/10 transition-colors">Cancel</button>
                    <button type="submit" disabled={uploadMutation.isLoading} className="btn-primary px-6 py-2 text-sm !bg-blue-500 hover:!bg-blue-600 shadow-[0_0_15px_rgba(59,130,246,0.3)]">
                      {uploadMutation.isLoading ? 'Uploading...' : 'Save Resource'}
                    </button>
                  </div>
                </form>
              </BaseCard>
            </motion.div>
          </div>
        )}
      </AnimatePresence>

    </div>
  );
};

export default ResourcesTab;
